// Taxonomy of the information / data categories an organisation may be obliged
// to provide to an end-user — spanning proactive disclosures, transactional
// records, and data-subject / portability outputs.
//
// Design is deliberately layered so the same data serves three views:
//   1. AU-anchored    — `basis.au` carries Australian statutory references.
//   2. Multi-juris.    — `basis.eu` (and future `basis.*`) carry parallel bases.
//   3. Standards-based — `rightType` is a jurisdiction-agnostic concept that the
//                        multi-jurisdiction mapping makes concrete; the UI can
//                        present this instead of any single statute.
//
// NOTE: statutory references are indicative pointers to help classify the data,
// not legal advice or an exhaustive citation.

export type Direction = "push" | "record" | "pull";
export type GroupId =
  | "records"
  | "disclosures"
  | "data-rights"
  | "account"
  | "ai"
  | "biometric"
  | "comms"
  | "tracking"
  | "identity"
  | "employment"
  | "marketing"
  | "security"
  | "special-category"
  | "sector";

export interface InfoCategory {
  id: string;
  name: string;
  group: GroupId;
  sector?: string; // set for group "sector"
  direction: Direction; // push = must provide, record = transaction artefact, pull = on request
  portability?: boolean; // relevant to a data-portability export
  rightType: string; // jurisdiction-agnostic concept (the "standards" spine)
  description: string;
  basis: { au?: string[]; eu?: string[] };
  appliesTo: string[]; // ANZSIC division ids, or ["all"]
  recommended?: boolean; // auto-selected when applicable to the chosen industry
  sensitive?: boolean; // special-category data (biometric, health, etc.)
}

export const DIRECTION_LABELS: Record<Direction, { label: string; hint: string }> = {
  push: { label: "Must provide", hint: "Organisation must proactively disclose this" },
  record: { label: "Transaction record", hint: "Artefact generated in dealing with the person" },
  pull: { label: "On request", hint: "The person can request or demand this back" },
};

